#include<bits/stdc++.h>
using namespace std;
const int MAXN = 3e7 + 10;
long long a[MAXN], ans[MAXN];
stack<long long>s;
int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)cin >> a[i];
	for(int i = 1; i <= n; i++){
		while(s.size() && a[i] > a[s.top()]) {
			int t = s.top();
			ans[t] = i;
			s.pop();
		}
		s.push(i);
	}
//	cout << endl;
	for(int i = 1; i <= n; i++)cout << ans[i] << " ";
}
